import {
  LOGIN_SUCCESS,
  LOGIN_ERROR,
  SET_USER,
  LOGOUT
} from './authTypes';

const initialState = {
  isAuth: false,
  user: null,
  error: null
};

export default function authReducer(state = initialState, action) {
  switch (action.type) {

    case LOGIN_SUCCESS:
      return {
        ...state,
        isAuth: true,
        user: action.payload,
        error: null
      };

    case SET_USER:
      return {
        ...state,
        isAuth: true,
        user: action.payload,
        error: null
      };

    case LOGIN_ERROR:
      return {
        ...state,
        isAuth: false,
        user: null,
        error: action.payload
      };

    case LOGOUT:
      return initialState;

    default:
      return state;
  }
}
